INSERT INTO translations (key, lang, value) VALUES ('bedside_btn_verify', 'en', 'Verify Compatibility') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('bedside_btn_verifying', 'en', 'Verifying...') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('bedside_desc', 'en', 'Scan Patient Wristband and Unit Barcode to ensure 100% compatibility before transfusion.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('bedside_step1', 'en', '1. Patient Profile (Simulating HIS/EHR Check)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('bedside_step2', 'en', '2. Scan Blood Unit (ISBT 128)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('bedside_sys_err', 'en', 'System error during verification') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('bedside_title', 'en', 'Bedside Verification') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_mdm_desc', 'en', 'Master Data Management (MDM) ensures multi-tenant isolation. System Admins can establish Organizations (Hubs, Blood Centers, Hospitals) and assign Users with specific RBAC roles (e.g., HospitalOperator, Dispatcher).') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_nav_mdm', 'en', 'MDM Configuration') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_nav_sop10', 'en', 'SOP 10: Hospital Ordering') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_nav_sop3', 'en', 'SOP 3: Hub Dispatch') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_nav_sop6', 'en', 'SOP 6: Bedside Verification') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_nav_sys', 'en', 'System Architecture') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sop10_desc', 'en', 'The hospital B2B ordering interface. Features a dynamic Searchable Combobox for quick Patient MRN selection. Clinical fields like "Indications" and "Special Needs" are tightly integrated. Also includes an emergency 1-click MTP (Massive Transfusion Protocol) activation.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sop3_desc', 'en', 'The Hub dispatch module utilizes the FEFO (First-Expire, First-Out) algorithm to prioritize unit safety. Displays strict warnings against ABO/RH compatibility overrides and provides 1-click autofill for target barcodes.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sop6_desc', 'en', 'Crucial double-nurse verification at the bedside. Requires strict scanning of ISBT-128 standard barcodes to prevent hemolytic transfusion reactions, alongside clinical checks (Vitals, Consent).') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_subtitle', 'en', 'System Overviews & Operational Manuals') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sys_desc', 'en', 'A clinical-grade BECS (Blood Establishment Computer System) built on a multi-tenant architecture. It seamlessly connects LIMS (Supply), Dispatch Hubs (Distribution), and Hospitals (Clinical), ensuring traceability and RBAC (Role-Based Access Control) data isolation.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sys_phases', 'en', 'Phase 1: Supply (LIMS). Phase 2: Dispatch (Hub). Phase 3: Clinical Verification (Hospital).') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sys_title', 'en', 'National Blood Management System') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
