INSERT INTO translations (key, lang, value) VALUES ('doc_mdm_desc', 'zh-TW', '主檔資料管理 (MDM) 是維護多租戶隔離的核心。管理員 (Admin) 必須先在此建立組織 (如各家醫院、HUB)，並配發專屬角色的使用者帳號。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_nav_mdm', 'zh-TW', 'MDM 後台管理') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
