INSERT INTO translations (key, lang, value) VALUES ('doc_nav_sys', 'zh-TW', '系統架構簡介') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sop10_desc', 'zh-TW', '醫院端 B2B 訂血介面。具備「動態捲動下拉選單 (Combobox)」可快速過濾龐大的病患 MRN。臨床適應症與特殊需求（如：洗滌、輻射照射）完整連動。遇到緊急狀況時可一鍵啟動大量輸血協定 (MTP)。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sop3_desc', 'zh-TW', 'HUB 倉庫派發模組內建 FEFO (先進先出) 演算法，自動建議即將到期的安全血袋。系統具備嚴格的 ABO/RH 相容性警示機制，並支援一鍵掃描自動填入目標條碼。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sop6_desc', 'zh-TW', '臨床端最重要的防線。透過掃描 ISBT-128 國際標準血袋條碼，搭配護理人員雙重核對 (Double-check) 以及生命徵象、同意書確認，徹底防範溶血性輸血反應。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_subtitle', 'zh-TW', '系統架構總覽與各模組詳細操作說明') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sys_desc', 'zh-TW', '本系統為具備多租戶 (Multi-tenant) 架構的臨床級血液管理平台 (BECS)。系統無縫串接 LIMS (血液供應端)、調度中心 (HUB 分配端) 與 醫院 (臨床端)，並透過嚴謹的 RBAC 角色存取控制確保資料隱私。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('doc_sys_phases', 'zh-TW', 'Phase 1: 血液供應 (LIMS) -> Phase 2: 調配物流 (Hub) -> Phase 3: 臨床驗證 (醫院)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
