INSERT INTO translations (key, lang, value) VALUES ('theme_desc_classic_editorial', 'zh-TW', '極致優雅的商務報表風格。仿麥肯錫戰略與學術研報，採用典雅象牙暖沙背景、經典高貴的襯線字體(Serif)、以及大氣沈穩的石板黑粗邊框。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
