INSERT INTO translations (key, lang, value) VALUES ('theme_name_warm_minimalist', 'zh-TW', '溫潤護眼大地燕麥 (Warm Earthy Oatmeal)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_warm_minimalist', 'zh-TW', '專為長期面對螢幕的醫護與臨床人員設計。以護眼燕麥暖灰色為基調，搭配細膩溫潤的卡片與陶土磚橘主色，營造舒緩溫和的工作氛圍。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_warm_minimalist', 'zh-TW', '燕麥暖沙與陶土磚橘') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_nordic_crisp', 'zh-TW', '北歐深林薄荷翠綠 (Nordic Forest Spruce)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_nordic_crisp', 'zh-TW', '清新、自然且令人耳目一新。採用典雅的 sage 鼠尾草綠背景，搭配極致純白卡片與濃郁深邃的松林翠綠按鈕，突顯專業、潔淨與生機。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_nordic_crisp', 'zh-TW', '鼠尾草綠與松林翠綠') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_classic_medical_blue', 'zh-TW', '經典皇家醫療藍 (Classic Royal Clinical Blue)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_classic_medical_blue', 'zh-TW', '最受國際醫療中心信賴的經典主色調。採用澄澈的天空淡藍背景、無暇純白卡片以及高對比的深海皇家藍按鈕，兼顧嚴謹度與易讀性。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_classic_medical_blue', 'zh-TW', '澄澈天空藍與皇家藍') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_oceanic_healing', 'zh-TW', '夕陽癒合溫馨珊瑚 (Sunset Healing Coral)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_oceanic_healing', 'zh-TW', '溫馨熱情且富有人道關懷氣息。結合柔和粉嫩的珊瑚暖白背景與耀眼奪目的夕陽紅主色，為冷冰冰的醫療管理系統注入一股療癒力量。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_oceanic_healing', 'zh-TW', '珊瑚粉暖白與夕陽紅') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
