INSERT INTO translations (key, lang, value) VALUES ('theme_desc_slate_corporate', 'zh-TW', '【戰術暗黑】專業的深海軍戰略指揮官介面。以深沉的冷鋼藍灰色背景，搭配發光亮眼的戰術青空藍(Cyan)按鈕，打造強烈的高科技操作感。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
