INSERT INTO translations (key, lang, value) VALUES ('theme_desc_tech_lavender', 'zh-TW', '【前沿暗黑】極具未來科技感的深邃暗黑風。深邃浩瀚的宇宙極黑背景搭配神秘墨靛藍卡片與高飽和度的霓虹薰衣草紫按鈕，對比強烈。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
