INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_clinical_legend_title', 'zh-TW', '血品臨床特性與適應症說明') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_rbc_desc', 'zh-TW', '適應症：用於提升嚴重貧血或活動性大出血患者的紅血球攜氧能力。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_plt_desc', 'zh-TW', '適應症：用於預防或治療嚴重血小板低下或血小板功能障礙引起之出血。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_ffp_desc', 'zh-TW', '適應症：用於大量出血時矯正凝血功能異常及補充凝血因子。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_cryo_desc', 'zh-TW', '富含纖維蛋白原及第八因子。適應症：嚴重低纖維蛋白原血症或 MTP 復甦程序中補給。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_wb_desc', 'zh-TW', '包含紅血球、血漿及血小板之全血。多用於軍事戰術醫療或急性創傷復甦搶救。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_abo_reg_title', 'zh-TW', 'ABO 強制核對 (ABO REG) 安全防護') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_abo_reg_warn', 'zh-TW', '關鍵安全防護：勾選此項後，系統將在發血前強制進行電腦交叉配血比對，比對「病患」與「血袋」的 ABO 血型以防止致命的急性溶血性輸血反應。') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
