INSERT INTO translations (key, lang, value) VALUES ('doc_sop3_desc', 'vi', 'Sử dụng thuật toán FEFO để ưu tiên xuất túi máu. Hiển thị cảnh báo nghiêm ngặt về tính tương thích ABO/RH và tự động điền mã vạch.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
