INSERT INTO translations (key, lang, value) VALUES ('doc_sys_desc', 'vi', 'Một BECS lâm sàng được xây dựng trên kiến trúc đa đối tượng thuê (Multi-tenant). Kết nối liền mạch LIMS (Cung cấp), Hub điều phối (Phân phối) và Bệnh viện (Lâm sàng), đảm bảo khả năng truy xuất nguồn gốc.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
