INSERT INTO translations (key, lang, value) VALUES ('ui_system_manual', 'vi', 'Hướng dẫn Hệ thống') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_title', 'vi', 'Cẩm nang Vận hành VN-BECS V1.0') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_subtitle', 'vi', 'Hướng dẫn chi tiết về kiến trúc chức năng và quy trình làm việc của Hệ thống Máy tính Cơ sở Truyền máu.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_portal_title', 'vi', 'Cổng Chỉ huy Thống nhất') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_portal_desc', 'vi', 'Hệ thần kinh trung ương của VN-BECS, cung cấp truy cập đăng nhập một lần và các số liệu quốc gia thời gian thực.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_lims_title', 'vi', 'LIMS: Tiếp nhận & Thu gom Người hiến') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_lims_desc', 'vi', 'Quản lý đăng ký người hiến, khảo sát sàng lọc sức khỏe và các quy trình lấy máu. Đảm bảo khả năng truy xuất nguồn gốc 100% ngay từ giọt máu đầu tiên.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_lab_title', 'vi', 'LAB: Trung tâm Kiểm tra & Chất lượng') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_lab_desc', 'vi', 'Đánh dấu bệnh truyền nhiễm tự động (NAT/Huyết thanh học) và định nhóm máu chính xác. Không có đơn vị nào được giải phóng mà không qua xác nhận 3 giai đoạn.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_hub_title', 'vi', 'HUB: Chuỗi cung ứng & Hậu cần') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_hub_desc', 'vi', 'Quản lý kho thông minh sử dụng thuật toán FEFO và theo dõi chuỗi lạnh tích hợp IoT để phân phối toàn quốc.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_hospital_title', 'vi', 'HOSPITAL: Truyền máu Lâm sàng') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_hospital_desc', 'vi', 'Đặt hàng tại điểm chăm sóc, xác minh mã vạch tại giường bệnh và quản lý Phác đồ Truyền máu Khối lượng lớn (MTP) khẩn cấp.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_national_title', 'vi', 'NATIONAL: Tình báo Chiến lược') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_national_desc', 'vi', 'Giám sát mạng lưới ở cấp độ vĩ mô cho kho máu quốc gia và mô hình mô phỏng khủng hoảng.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_mdm_title', 'vi', 'MDM: Quản trị Dữ liệu Gốc') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('manual_mdm_desc', 'vi', 'Quản trị toàn cầu các nút tổ chức, RBAC người dùng và danh mục sản phẩm ISBT-128.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
