INSERT INTO translations (key, lang, value) VALUES ('theme_name_classic_editorial', 'vi', 'McKinsey Doanh nghiệp Bản in (Phiến thạch ngà)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_classic_editorial', 'vi', 'Phong cách báo cáo doanh nghiệp cực kỳ trang nhã. Lấy cảm hứng từ các báo cáo tư vấn của McKinsey với nền cát ngà ấm áp, kiểu chữ serif tinh tế và viền đen phiến thạch đậm.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_classic_editorial', 'vi', 'Cát Ngà & Kiểu chữ Serif') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_warm_minimalist', 'vi', 'Yến mạch Đất ấm (Bảo vệ Mắt)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_warm_minimalist', 'vi', 'Được thiết kế đặc biệt cho ca làm việc dài. Mang lại nền xám yến mạch ấm áp làm dịu mắt, kết hợp với các nút màu cam đất ấm để giảm mỏi mắt cho nhân viên y tế.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_warm_minimalist', 'vi', 'Cát Yến Mạch & Cam Đất') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_nordic_crisp', 'vi', 'Thông Rừng Bắc Âu (Sage Tươi)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_nordic_crisp', 'vi', 'Tươi mới, tự nhiên và tràn đầy sức sống. Nổi bật với nền xanh sage thanh lịch kết hợp với thẻ trắng lâm sàng tinh khiết và nút bấm xanh thông đậm, thể hiện tính chuyên nghiệp và sinh khí.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_nordic_crisp', 'vi', 'Xanh Sage & Xanh Thông') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_classic_medical_blue', 'vi', 'Xanh Lâm sàng Hoàng gia Cổ điển') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_classic_medical_blue', 'vi', 'Tiêu chuẩn đáng tin cậy tại các trung tâm y tế toàn cầu. Kết hợp nền xanh da trời trong vắt, bảng màu trắng nguyên sơ và nút màu xanh hoàng gia tương phản cao để tối ưu hóa khả năng đọc.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_classic_medical_blue', 'vi', 'Xanh Da Trời & Xanh Hoàng Gia') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_oceanic_healing', 'vi', 'San hô Sunset Chữa lành (Nhân văn)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_oceanic_healing', 'vi', 'Ấm áp, nhiệt huyết và giàu lòng nhân ái. Pha trộn giữa nền trắng san hô nhẹ nhàng với màu cam đỏ hoàng hôn rực rỡ tiếp thêm sinh lực điều trị cho các giao diện lâm sàng.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_oceanic_healing', 'vi', 'San Hô & Đỏ Hoàng Hôn') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_slate_corporate', 'vi', 'Chỉ huy Thép Chiến thuật (Dark)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_slate_corporate', 'vi', '[Tactical Dark] Môi trường chiến thuật của chỉ huy quân sự chuyên nghiệp. Nền xanh phiến thạch thép sâu kết hợp với các chỉ báo màu xanh cyan phát sáng đậm chất công nghệ cao.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_slate_corporate', 'vi', 'Thép Slate & Lam Sáng') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_tech_lavender', 'vi', 'Oải hương Cyber Lâm sàng (Dark)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_tech_lavender', 'vi', '[Frontier Dark] Tông màu y tế điều khiển học tương lai cực kỳ hiện đại. Nền vũ trụ đen huyền bí xếp lớp với các bảng màu chàm đậm và bộ điều khiển hoa oải hương phát sáng mạnh mẽ.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_tech_lavender', 'vi', 'Đen Đêm & Tím Neon') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_minty_aqua', 'vi', 'Thiết bị đầu cuối CRT Cổ điển (Geek)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_minty_aqua', 'vi', '[Console Geek] Sự tri ân hoài cổ dành cho màn hình đơn sắc CRT xanh phospho cổ điển. Nền đen tuyền với các bảng xanh lục đậm, chữ màu xanh lá ma trận phát sáng và phông chữ monospace.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_minty_aqua', 'vi', 'Xanh Phospho & Monospace') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_frosted_glacier', 'vi', 'Kính Băng hà Mờ (Light Glass)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_frosted_glacier', 'vi', '[Luminous Glass] Độ trong suốt như pha lê tuyệt đẹp. Nổi bật với nền băng xanh lạnh với thẻ kính mờ có độ mờ cao và các nút màu xanh bầu trời rực rỡ.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_frosted_glacier', 'vi', 'Xanh Băng & Kính Mờ') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_name_aurora_glow', 'vi', 'Mơ mộng Tinh vân Cực quang (Dark Glass)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_desc_aurora_glow', 'vi', '[Nebular Dark Glass] Dòng chảy vũ trụ huyền ảo và lãng mạn. Sử dụng nền cực quang tím hồng tuyệt đẹp xếp lớp với các thẻ màu tím đậm trong suốt và các nút màu hồng rực rỡ.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('theme_accent_aurora_glow', 'vi', 'Tinh Vân Vũ Trụ & Kính Tím') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_matrix_desc', 'vi', 'Ma trận này xác định vai trò tài khoản nào có thể đăng nhập vào phân hệ hệ thống nào. Bấm vào ô chọn để phân bổ quyền động.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
