INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_lims_title', 'vi', '🔵 Phòng Lab & Lâm sàng (LIMS & Hospital)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_lims_desc_1', 'vi', 'DonorScreener / Nurse: Chịu trách nhiệm đăng ký quầy tiếp đón và lấy máu LIMS.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_lims_desc_2', 'vi', 'LIMS_Simulator / QA_Officer: Chịu trách nhiệm xét nghiệm sàng lọc phòng thí nghiệm LIMS và duyệt QA.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_lims_desc_3', 'vi', 'HospitalOperator: Chịu trách nhiệm quản lý tồn kho máu và đặt hàng phía bệnh viện.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_hub_title', 'vi', '🟡 Lưu kho & Hậu cần (HUB)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_hub_desc_1', 'vi', 'WarehouseIssuer: Chịu trách nhiệm nhập kho HUB và cấp phát sản phẩm máu.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_hub_desc_2', 'vi', 'Dispatcher: Chịu trách nhiệm điều phối đội xe HUB và phân bổ phương tiện.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_hub_desc_3', 'vi', 'Courier: Chịu trách nhiệm vận chuyển chuỗi lạnh và theo dõi nhiệt độ trên đường.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_admin_title', 'vi', '🟣 Quản trị & Bảng giám sát (Admin & Dashboards)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_admin_desc_1', 'vi', 'Manager: Có thể truy cập các bảng giám sát phân hệ để theo dõi vận hành.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_admin_desc_2', 'vi', 'Admin: Quyền gốc toàn hệ thống, có thể sửa đổi ma trận vai trò phân hệ trong MDM.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_policy_admin_warn', 'vi', '⚠️ Quyền hạn được liên kết toàn cầu; để đảm bảo quy trình bình thường, khuyến nghị không nên tự ý thay đổi.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
