INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_clinical_legend_title', 'vi', 'Hồ sơ Lâm sàng & Chỉ định của Sản phẩm Máu') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_rbc_desc', 'vi', 'Chỉ định: Dùng để nâng cao khả năng vận chuyển oxy trong trường hợp thiếu máu nghiêm trọng hoặc xuất huyết cấp tính.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_plt_desc', 'vi', 'Chỉ định: Dùng để phòng ngừa/điều trị chảy máu do giảm tiểu cầu nặng hoặc rối loạn chức năng tiểu cầu.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_ffp_desc', 'vi', 'Chỉ định: Dùng để điều chỉnh bệnh đông máu và thay thế các yếu tố đông máu khi chảy máu ồ ạt.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_cryo_desc', 'vi', 'Giàu fibrinogen và Yếu tố VIII. Chỉ định: Dùng khi giảm fibrinogen máu nặng hoặc trong hồi sức cấp cứu MTP.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_legend_wb_desc', 'vi', 'Máu toàn phần chứa hồng cầu, huyết tương và tiểu cầu. Được dùng trong y học chiến thuật quân sự hoặc hồi sức chấn thương cấp tính.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_abo_reg_title', 'vi', 'Bảo vệ Bắt buộc ABO (ABO REG)') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_abo_reg_warn', 'vi', 'BẢO VỆ AN TOÀN QUAN TRỌNG: Nếu tích chọn, hệ thống sẽ thực hiện kiểm tra chéo máy tính nghiêm ngặt so sánh nhóm máu của bệnh nhân và túi máu để ngăn ngừa phản ứng truyền máu tan máu cấp tính gây tử vong.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_cat_abo_status_active', 'vi', 'Cơ chế xác thực tự động ISBT-128 hoạt động.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
