INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_hint_title', 'vi', 'Đồng bộ hóa ma trận RBAC') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('mdm_rbac_hint_desc', 'vi', 'Lưu ý: Việc sửa đổi quyền của vai trò trong tab RBAC sẽ cập nhật động quy tắc ủy quyền hệ thống cho tất cả các tài khoản tương ứng ở phiên đăng nhập tiếp theo.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage1_title', 'vi', '✅ Đã Đăng Ký Người Hiến Máu') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage1_msg', 'vi', 'Đăng ký người hiến máu hoàn tất. Vui lòng chuyển đến ''2. Sàng Lọc'' để kiểm tra sức khỏe trước khi lấy máu.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage1_btn', 'vi', 'Đi tới Sàng Lọc →') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage2_title', 'vi', '🧪 Kiểm Tra IDM Hoàn Tất') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage2_msg', 'vi', 'Đã hoàn tất kiểm tra dấu ấn bệnh truyền nhiễm (IDM). Nếu kết quả là CLEARED, vui lòng chuyển đến ''3. Xử Lý Thành Phần''.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage2_btn', 'vi', 'Đi Tới Xử Lý Thành Phần →') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage3_title', 'vi', '🩸 Thành Phần Máu Đã Xử Lý') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage3_msg', 'vi', 'Hoàn tất tách thành phần máu. Vui lòng chuyển đến ''4. Phát Hành & Vận Chuyển'' để QA phát hành.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage3_btn', 'vi', 'Đi Tới Phát Hành & Vận Chuyển →') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage4_title', 'vi', '🚀 Đã Phát Hành Đến Trung Tâm') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO translations (key, lang, value) VALUES ('lims_toast_stage4_msg', 'vi', 'Túi máu {compId} đã được đồng bộ hóa thành công tới trung tâm điều phối. Bạn có thể quay lại Cổng thông tin để theo dõi tại Trạm HUB.') ON CONFLICT (key, lang) DO UPDATE SET value = EXCLUDED.value;
